import { ServiceError } from "../types.js";
import type { CreateOrderInput } from "../types.js";

const router = Router();

function httpStatus(code: string): number {
  switch (code) {
    case "NOT_FOUND": return 404;
    case "VALIDATION_ERROR": return 400;
    case "CONFLICT": return 400;
    default: return 500;
  }
}

router.get("/orders", (req, res) => {
  const { userId, status } = req.query;
  const result = listOrders({
    userId: typeof userId === "string" ? parseInt(userId, 10) : undefined,
    status: typeof status === "string" ? status : undefined,
  });
  res.json(result);
});

router.get("/orders/:id", (req, res) => {
  try {
    const order = getOrder(parseInt(req.params.id, 10));
    res.json(order);
  } catch (e) {
    if (e instanceof ServiceError) {
      res.status(httpStatus(e.code)).json({ error: e.message });
      return;
    }
    throw e;
  }
});

router.post("/orders", (req, res) => {
  try {
    const order = createOrder(req.body as CreateOrderInput);
    res.status(201).json(order);
  } catch (e) {
    if (e instanceof ServiceError) {
      res.status(httpStatus(e.code)).json({ error: e.message });
      return;
    }
    throw e;
  }
});

router.patch("/orders/:id/status", (req, res) => {
  try {
    const { status } = req.body as { status: string };
